/* === Twitch Sankagata Manager · landing page runtime ===
 *
 * Per-language HTML is generated by site/build.mjs at build time, so this
 * script no longer translates anything at runtime. It handles only:
 *   1. footer year auto-update
 *   2. floating star particles in the hero
 *   3. OS auto-detect badge on the matching download card
 *   4. live changelog + download asset metadata fetched from GitHub Releases
 *   5. scroll-triggered reveal choreography
 *
 * The i18n dict lives in site/i18n.mjs and is consumed only by the build
 * script. The lang-pill is now a set of <a> nav links (also generated by
 * the build script), so no JS is required to switch language.
 */

const REPO = "acerola/twitch-sankagata-manager";
const RELEASES_API = `https://api.github.com/repos/${REPO}/releases`;
const RELEASES_PAGE = `https://github.com/${REPO}/releases`;
const PLACEHOLDER_RELEASE_NOTES = new Set(["build in progress."]);

// Per-OS asset variants. `primary` populates the main download button,
// `alt` populates the secondary text link beneath it.
// Windows leads with the portable .zip — no install, no SmartScreen
// detour, just unzip and run.
const PLATFORM_VARIANTS = {
  windows: {
    primary: /x64_portable\.zip$/i,
    alt: /x64-setup\.exe$/i,
  },
  macos: {
    primary: /universal\.dmg$/i,
    alt: null,
  },
};

const REVEAL_SELECTOR = [
  ".section-head",
  ".card",
  ".preview-wrap",
  ".step",
  ".dl-wrap",
  ".faq-item",
  ".log-entry",
].join(",");

const reduceMotion = window.matchMedia("(prefers-reduced-motion: reduce)");
let revealObserver = null;

(function copyrightYear() {
  const el = document.getElementById("copyright-year");
  if (el) el.textContent = String(new Date().getFullYear());
})();

(function makeStars() {
  const root = document.getElementById("stars");
  if (!root) return;
  const colors = ["var(--neon-yel)", "var(--neon-cyan)", "var(--neon-mag)"];
  const N = 18;
  for (let i = 0; i < N; i++) {
    const s = document.createElement("span");
    s.className = "star";
    const size = 8 + Math.random() * 14;
    const left = Math.random() * 100;
    const dur = 14 + Math.random() * 14;
    const delay = -Math.random() * dur;
    const c = colors[Math.floor(Math.random() * colors.length)];
    const opacity = 0.4 + Math.random() * 0.5;
    const driftX = (Math.random() - 0.5) * 80 + "px";
    s.style.cssText = `
      left: ${left}%;
      top: 0;
      --s: ${size}px;
      --d: ${dur}s;
      --c: ${c};
      --o: ${opacity};
      --x: ${driftX};
      --delay: ${delay}s;
      animation-delay: ${delay}s;
    `;
    s.innerHTML = `<svg viewBox="0 0 24 24" fill="currentColor"><path d="M12 1.5l2.6 7 7.4.6-5.6 4.9 1.7 7.3L12 17.6 5.9 21.3l1.7-7.3L2 9.1l7.4-.6z"/></svg>`;
    root.appendChild(s);
  }
})();

(function detectOS() {
  const ua = navigator.userAgent || "";
  const platform = navigator.platform || "";
  let os = null;
  if (/Win/i.test(platform) || /Windows/i.test(ua)) os = "windows";

  if (!os) return;
  const card = document.querySelector(`.dl-card[data-os="${os}"]`);
  if (card && !card.classList.contains("is-soon")) {
    const tag = document.createElement("span");
    tag.className = "dl-detected-tag";
    tag.textContent = "DETECTED";
    card.appendChild(tag);
  }
})();

function queueRevealTargets(root = document) {
  const targets = [
    ...(root.matches?.(REVEAL_SELECTOR) ? [root] : []),
    ...root.querySelectorAll(REVEAL_SELECTOR),
  ];

  targets.forEach((el, index) => {
    if (el.classList.contains("reveal")) return;

    el.classList.add("reveal");
    el.style.setProperty("--reveal-delay", `${Math.min(index % 6, 5) * 70}ms`);

    if (reduceMotion.matches || !revealObserver) {
      el.classList.add("is-visible");
      return;
    }

    revealObserver.observe(el);
  });
}

(function setupScrollReveals() {
  if (!("IntersectionObserver" in window) || reduceMotion.matches) {
    queueRevealTargets();
    return;
  }

  revealObserver = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        entry.target.classList.toggle("is-visible", entry.isIntersecting);
      });
    },
    { rootMargin: "-8% 0px -10% 0px", threshold: 0.12 },
  );

  queueRevealTargets();
})();

async function loadReleases() {
  try {
    const res = await fetch(RELEASES_API, {
      headers: { Accept: "application/vnd.github+json" },
    });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const releases = await res.json();
    const publicReleases = Array.isArray(releases)
      ? releases.filter(isPublicRelease)
      : [];
    const downloadableReleases = publicReleases.filter(hasDownloadAsset);
    const changelogReleases = publicReleases.filter(hasReleaseNotes);
    if (publicReleases.length === 0) {
      paintFallback();
      return;
    }
    paintLatest(downloadableReleases[0] || publicReleases[0]);
    paintChangelog(changelogReleases.slice(0, 3));
  } catch (err) {
    console.warn("release fetch failed", err);
    paintFallback();
  }
}

function isPublicRelease(rel) {
  return rel && !rel.draft && !rel.prerelease && rel.published_at;
}

function hasDownloadAsset(rel) {
  const assets = rel.assets || [];
  return Object.values(PLATFORM_VARIANTS).some((variants) =>
    [variants.primary, variants.alt].some(
      (regex) => regex && assets.some((asset) => regex.test(asset.name || "")),
    ),
  );
}

function hasReleaseNotes(rel) {
  const body = (rel.body || "").trim();
  return body && !PLACEHOLDER_RELEASE_NOTES.has(body.toLowerCase());
}

function paintLatest(rel) {
  const tag = rel.tag_name || "—";
  const date = rel.published_at
    ? new Date(rel.published_at).toLocaleDateString(undefined, {
        year: "numeric",
        month: "short",
        day: "numeric",
      })
    : "—";

  document
    .querySelectorAll("[data-latest-version]")
    .forEach((el) => (el.textContent = tag));

  const dlVersion = document.getElementById("dl-version");
  if (dlVersion) dlVersion.textContent = `${tag} · ${date}`;

  const grid = document.querySelector("[data-download-grid]");
  if (!grid) return;
  const assets = rel.assets || [];
  const findAsset = (regex) => regex && assets.find((a) => regex.test(a.name));
  const formatSize = (bytes) => `${(bytes / 1024 / 1024).toFixed(1)} MB`;

  for (const [os, variants] of Object.entries(PLATFORM_VARIANTS)) {
    const card = grid.querySelector(`[data-os="${os}"]`);
    if (!card) continue;

    const primary = findAsset(variants.primary);
    const fileEl = card.querySelector("[data-os-file]");
    const linkEl = card.querySelector("[data-os-link]");
    if (primary && fileEl && linkEl) {
      const ext = primary.name.split(".").pop().toLowerCase();
      fileEl.textContent = `${formatSize(primary.size)} · .${ext}`;
      linkEl.href = primary.browser_download_url;
    } else if (fileEl) {
      fileEl.textContent = "asset not yet uploaded";
    }

    const altLinkEl = card.querySelector("[data-os-alt-link]");
    const altSizeEl = card.querySelector("[data-os-alt-size]");
    const alt = findAsset(variants.alt);
    if (altLinkEl) {
      if (alt) {
        altLinkEl.href = alt.browser_download_url;
        altLinkEl.hidden = false;
        if (altSizeEl) altSizeEl.textContent = formatSize(alt.size);
      } else {
        altLinkEl.hidden = true;
      }
    }
  }
}

function paintChangelog(releases) {
  const log = document.querySelector("[data-changelog]");
  if (!log) return;
  if (!releases.length) {
    log.innerHTML = '<p class="log-empty">No releases yet.</p>';
    return;
  }
  log.innerHTML = releases.map(renderEntry).join("");
  queueRevealTargets(log);
}

function renderEntry(rel) {
  const tag = escape(rel.tag_name || "—");
  const date = rel.published_at
    ? new Date(rel.published_at).toLocaleDateString(undefined, {
        year: "numeric",
        month: "short",
        day: "numeric",
      })
    : "—";
  const body = markdownLite(rel.body || "_no notes_");
  return `
    <article class="log-entry">
      <div class="log-version">${tag} <span class="date">${escape(date)}</span></div>
      <div class="log-content">${body}</div>
    </article>`;
}

function paintFallback() {
  document
    .querySelectorAll("[data-latest-version]")
    .forEach((el) => (el.textContent = "latest"));
  const dlVersion = document.getElementById("dl-version");
  if (dlVersion) dlVersion.textContent = "no release yet";

  document
    .querySelectorAll("[data-download-grid] [data-os-file]")
    .forEach((el) => {
      el.textContent = "no release yet";
    });

  const log = document.querySelector("[data-changelog]");
  if (log) {
    log.innerHTML = `<p class="log-empty">Releases will appear here after the first publish. <a href="${RELEASES_PAGE}" target="_blank" rel="noopener" style="color:var(--neon-cyan)">View on GitHub →</a></p>`;
  }
}

function markdownLite(md) {
  const safe = escape(md);
  return safe
    .replace(/^### (.*)$/gm, "<h4>$1</h4>")
    .replace(/^## (.*)$/gm, "<h3>$1</h3>")
    .replace(/^- (.*)$/gm, "<li>$1</li>")
    .replace(/(<li>.*?<\/li>\s*)+/gs, (m) => `<ul>${m}</ul>`)
    .replace(/`([^`]+)`/g, "<code>$1</code>")
    .replace(
      /\[([^\]]+)\]\(([^)]+)\)/g,
      '<a href="$2" target="_blank" rel="noopener">$1</a>',
    )
    .replace(/\n{2,}/g, "</p><p>")
    .replace(/^(?!<[uh]|<p|<li|<\/)([^\n]+)$/gm, "<p>$1</p>");
}

function escape(s) {
  return String(s)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}

loadReleases();
